import 'package:flutter/foundation.dart';
import '../models/enquiry_model.dart';
import '../services/api_service.dart';

class EnquiryProvider extends ChangeNotifier {
  final ApiService _apiService = ApiService();

  List<Enquiry> _enquiries = [];
  bool _isLoading = false;
  String? _error;

  List<Enquiry> get enquiries => _enquiries;
  bool get isLoading => _isLoading;
  String? get error => _error;

  Future<void> fetchEnquiries({String? status, int page = 1}) async {
    _isLoading = true;
    _error = null;
    notifyListeners();

    try {
      final endpoint = '/enquiries?page=$page&limit=10${status != null ? '&status=$status' : ''}';
      final response = await _apiService.get(endpoint);

      if (response['success'] == true) {
        final List<dynamic> data = response['data']['enquiries'] ?? [];
        _enquiries = data.map((e) => Enquiry.fromJson(e)).toList();
        notifyListeners();
      } else {
        _error = response['error'] ?? 'Failed to fetch enquiries';
        notifyListeners();
      }
    } catch (e) {
      _error = e.toString();
      notifyListeners();
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  Future<bool> createEnquiry({
    required String customerName,
    required String customerPhone,
    String? customerEmail,
    String? customerAddress,
    String? notes,
  }) async {
    try {
      final response = await _apiService.post(
        '/enquiries',
        body: {
          'customerName': customerName,
          'customerEmail': customerEmail,
          'customerPhone': customerPhone,
          'customerAddress': customerAddress,
          'notes': notes,
        },
      );

