using AutoMapper;
using Microsoft.EntityFrameworkCore;
using SalesQuotation.Application.Dtos;
using SalesQuotation.Domain.Entities;
using SalesQuotation.Infrastructure.Data;
using System.Text.Json;

namespace SalesQuotation.Application.Services;

public class MeasurementService : IMeasurementService
{
    private readonly ApplicationDbContext _context;
    private readonly IMapper _mapper;

    public MeasurementService(ApplicationDbContext context, IMapper mapper)
    {
        _context = context;
        _mapper = mapper;
    }

    public async Task<MeasurementDto> AddMeasurementAsync(Guid enquiryId, CreateMeasurementDto dto, Guid createdById)
    {
        var enquiry = await _context.Enquiries.FindAsync(enquiryId);
        if (enquiry == null)
            throw new InvalidOperationException("Enquiry not found");

        var category = await _context.MeasurementCategories.FindAsync(dto.CategoryId);
        if (category == null)
            throw new InvalidOperationException("Measurement category not found");

        // Calculate value based on measurement data
        var calculatedValue = await CalculateMeasurementAsync(category.CategoryKey, dto.MeasurementData);

        var measurement = new Measurement
        {
            Id = Guid.NewGuid(),
            EnquiryId = enquiryId,
            CategoryId = dto.CategoryId,
            MeasurementData = JsonSerializer.Serialize(dto.MeasurementData),
            CalculatedValue = calculatedValue,
            Notes = dto.Notes,
            CreatedById = createdById,
            CreatedAt = DateTime.UtcNow
        };

        _context.Measurements.Add(measurement);
        await _context.SaveChangesAsync();

        return _mapper.Map<MeasurementDto>(measurement);
    }

    public async Task<IEnumerable<MeasurementDto>> GetMeasurementsByEnquiryAsync(Guid enquiryId)
    {
        var measurements = await _context.Measurements
            .Where(m => m.EnquiryId == enquiryId)
            .Include(m => m.Category)
            .OrderByDescending(m => m.CreatedAt)
            .ToListAsync();

        return _mapper.Map<IEnumerable<MeasurementDto>>(measurements);
    }

    public async Task<IEnumerable<MeasurementCategoryDto>> GetCategoriesAsync()
    {
        var categories = await _context.MeasurementCategories
            .Where(c => c.IsActive)
            .OrderBy(c => c.CategoryName)
            .ToListAsync();

        return _mapper.Map<IEnumerable<MeasurementCategoryDto>>(categories);
    }

    public async Task<decimal> CalculateMeasurementAsync(string categoryKey, Dictionary<string, decimal> measurementData)
    {
        // Formula for different measurement types
        return categoryKey switch
        {
            "FLOORING" => (measurementData["length"] * measurementData["breadth"]) * 10.764m, // m² to sq.ft
            "WALL_CLADDING" => (measurementData["height"] * measurementData["width"]) * 10.764m,
            "PAINTING" => (measurementData["height"] * measurementData["width"]) * 10

